/**
 * POLLN Configuration Tiers
 *
 * Auto-generated from Pareto-optimal configurations
 * Generated by: simulations/advanced/multiobjective/run_all.py
 *
 * Categories:
 * - Accuracy vs Cost
 * - Speed vs Quality
 * - Robustness vs Efficiency
 * - Scalability vs Complexity
 *
 * Usage:
 * ```typescript
 * import { CONFIG_TIERS } from '@polln/core/config/tiers';
 *
 * // Use budget tier
 * const config = CONFIG_TIERS.ACCURACY_COST_BUDGET;
 *
 * // Use production scenario
 * import productionConfig from './scenarios.json';
 * ```
 */

export interface PollnConfigTier {
  // Model parameters
  model_size?: string;
  checkpoint_frequency?: number;
  cache_size?: string;
  kv_cache_size?: string;

  // Inference parameters
  batch_size?: number;
  compression_level?: number;
  temperature?: number;
  top_p?: number;
  max_tokens?: number;

  // Reliability parameters
  replication_factor?: number;
  monitoring_level?: number;
  backup_enabled?: boolean;
  backup_frequency_hours?: number;
  health_check_interval_sec?: number;
  circuit_breaker_threshold?: number;
  retry_policy?: string;
  max_retries?: number;
  timeout_multiplier?: number;
  use_quorum?: boolean;
  disaster_recovery_enabled?: boolean;

  // Scalability parameters
  colony_size?: number;
  topology_depth?: number;
  agent_types?: number;
  decentralization_level?: number;
  horizontal_scaling?: boolean;
  auto_scaling?: boolean;
  load_balancing_strategy?: string;
  cache_sharding?: boolean;
  federation_enabled?: boolean;
  meta_tile_ratio?: number;
  communication_pattern?: string;

  // Advanced features
  use_speculative_decoding?: boolean;
  use_quantization?: boolean;
  use_federated?: boolean;

  // Expected metrics
  expected_accuracy?: number;
  expected_latency_ms?: number;
  expected_availability?: string;
  expected_throughput?: number;
  expected_cost_multiplier?: number;
  expected_complexity?: number;
  expected_hourly_cost?: number;

  // Target objective
  target: string;
}

