/**
 * Helper function to get configuration by tier name
 */
export function getConfig(tierName: string): PollnConfigTier | undefined {
  return CONFIG_TIERS[tierName];
}

/**
 * Helper function to get scenario configuration
 */
export function getScenarioConfig(scenarioName: string): PollnConfigTier | undefined {
  return SCENARIO_CONFIGS[scenarioName];
}

/**
 * Helper function to merge multiple configurations
 */
export function mergeConfigs(...configs: Partial<PollnConfigTier>[]): PollnConfigTier {
  return Object.assign({}, ...configs) as PollnConfigTier;
}

/**
 * Helper function to validate configuration meets constraints
 */
export function validateConfig(
  config: PollnConfigTier,
  constraints: Partial<{
    max_latency_ms: number;
    min_availability: number;
    max_cost_multiplier: number;
    min_accuracy: number;
  }>
): boolean {
  if (constraints.max_latency_ms && config.expected_latency_ms) {
    if (config.expected_latency_ms > constraints.max_latency_ms) {
      return false;
    }
  }

  if (constraints.min_availability && config.expected_availability) {
    const availability = parseFloat(config.expected_availability);
    if (availability < constraints.min_availability * 100) {
      return false;
    }
  }

  if (constraints.max_cost_multiplier && config.expected_cost_multiplier) {
    if (config.expected_cost_multiplier > constraints.max_cost_multiplier) {
      return false;
    }
  }

  if (constraints.min_accuracy && config.expected_accuracy) {
    if (config.expected_accuracy < constraints.min_accuracy) {
      return false;
    }
  }

  return true;
}

export default CONFIG_TIERS;
